mapper.select:
select * from `exam_record`

     and id = #{id}
     and exam_id = #{examId}
     and student_id = #{studentId}

order by id desc

mapper.update:
update `exam_record`
exam_id = #{examId}, student_id = #{studentId}, score = #{score}, submit_time = #{submitTime}, status = #{status}, remark = #{remark}, create_time = #{createTime}, update_time = #{updateTime},
where id = #{id}
